export class HashMap {
  constructor() {
    this.buckets = new Map();
    this.order = [];
  }

  set(key, value) {
    if (!this.buckets.has(key)) this.order.push(key);
    this.buckets.set(key, value);
  }

  get(key) {
    return this.buckets.has(key) ? this.buckets.get(key) : null;
  }

  has(key) {
    return this.buckets.has(key);
  }

  keys() {
    return [...this.order];
  }
}

