export class SinglyLinkedList {
  constructor() {
    this.head = null;
    this.length = 0;
  }

  toArray() {
    const out = [];
    let curr = this.head;
    while (curr) {
      out.push(curr.val);
      curr = curr.next;
    }
    return out;
  }

  append(val) {
    const node = new Node(val);
    if (!this.head) {
      this.head = node;
    } else {
      let curr = this.head;
      while (curr.next) curr = curr.next;
      curr.next = node;
    }
    this.length += 1;
  }

  prepend(val) {
    this.head = new Node(val, this.head);
    this.length += 1;
  }

  insertAt(index, val) {
    if (index < 0 || index > this.length) return null;
    if (index === 0) {
      this.prepend(val);
      return val;
    }
    let curr = this.head;
    for (let i = 0; i < index - 1; i += 1) curr = curr.next;
    curr.next = new Node(val, curr.next);
    this.length += 1;
    return val;
  }

  removeAt(index) {
    if (index < 0 || index >= this.length) return null;
    if (index === 0) {
      const removed = this.head.val;
      this.head = this.head.next;
      this.length -= 1;
      return removed;
    }
    let curr = this.head;
    for (let i = 0; i < index - 1; i += 1) curr = curr.next;
    const removed = curr.next.val;
    curr.next = curr.next.next;
    this.length -= 1;
    return removed;
  }
}

