export class DoublyLinkedList {
  constructor() {
    this.head = null;
    this.tail = null;
  }

  toArray() {
    const out = [];
    let curr = this.head;
    while (curr) {
      out.push(curr.val);
      curr = curr.next;
    }
    return out;
  }

  append(val) {
    const node = new Node(val);
    if (!this.head) {
      this.head = this.tail = node;
    } else {
      node.prev = this.tail;
      this.tail.next = node;
      this.tail = node;
    }
  }

  prepend(val) {
    const node = new Node(val);
    if (!this.head) {
      this.head = this.tail = node;
    } else {
      node.next = this.head;
      this.head.prev = node;
      this.head = node;
    }
  }

  remove(val) {
    let curr = this.head;
    while (curr) {
      if (curr.val === val) {
        if (curr.prev) curr.prev.next = curr.next;
        else this.head = curr.next;
        if (curr.next) curr.next.prev = curr.prev;
        else this.tail = curr.prev;
        return true;
      }
      curr = curr.next;
    }
    return false;
  }
}

export class Stack {
  constructor() {
    this.items = [];
