export class Queue {
  constructor() {
    this.items = [];
    this.head = 0;
  }

  enqueue(val) {
    this.items.push(val);
  }

  dequeue() {
    if (this.isEmpty()) return null;
    return this.items[this.head++];
  }

  peek() {
    return this.isEmpty() ? null : this.items[this.head];
  }

  isEmpty() {
    return this.head >= this.items.length;
  }
}

