export class BST {
  constructor() {
    this.root = null;
  }

  insert(val) {
    const add = (node) => {
      if (!node) return new Node(val);
      if (val < node.val) node.left = add(node.left);
      else if (val > node.val) node.right = add(node.right);
      return node;
    };
    this.root = add(this.root);
  }

  search(val) {
    let node = this.root;
    while (node) {
      if (val === node.val) return true;
      node = val < node.val ? node.left : node.right;
    }
    return false;
  }

  inorder() {
    const out = [];
    const walk = (node) => {
      if (!node) return;
      walk(node.left);
      out.push(node.val);
      walk(node.right);
    };
    walk(this.root);
    return out;
  }

  remove(val) {
    const minValue = (node) => {
      while (node.left) node = node.left;
      return node.val;
    };

    const del = (node, target) => {
      if (!node) return null;
      if (target < node.val) node.left = del(node.left, target);
      else if (target > node.val) node.right = del(node.right, target);
      else {
        if (!node.left) return node.right;
        if (!node.right) return node.left;
        const successor = minValue(node.right);
        node.val = successor;
        node.right = del(node.right, successor);
      }
      return node;
    };

    const before = this.search(val);
    if (!before) return false;
    this.root = del(this.root, val);
    return true;
  }
}

export class Trie {
  constructor() {
    this.root = {};
  }

  insert(word) {
    let node = this.root;
    for (const ch of word) {
      if (!node[ch]) node[ch] = {};
      node = node[ch];
    }
    node.$ = true;
  }

  traverse(word) {
    let node = this.root;
    for (const ch of word) {
      if (!node[ch]) return null;
      node = node[ch];
    }
    return node;
  }

  search(word) {
    const node = this.traverse(word);
    return !!(node && node.$);
  }

  startsWith(prefix) {
    return this.traverse(prefix) !== null;
  }
}

export function buildAdjacencyList(edges, directed = false) {
  const graph = {};
  const add = (a, b) => {
    if (!graph[a]) graph[a] = [];
    if (!graph[a].includes(b)) graph[a].push(b);
    graph[a].sort();
  };

  for (const [from, to] of edges) {
    add(from, to);
    if (!directed) add(to, from);
  }
  return graph;
}

export function dfs(graph, start) {
  if (!(start in graph)) return [];
  const visited = new Set();
  const order = [];

  const walk = (node) => {
    visited.add(node);
    order.push(node);
    for (const neighbor of graph[node]) {
      if (!visited.has(neighbor)) walk(neighbor);
    }
  };

  walk(start);
  return order;
}

export function reverseStringRecursive(s) {
  if (s.length <= 1) return s;
  return reverseStringRecursive(s.slice(1)) + s[0];
}

export function bubbleSort(nums) {
  const arr = [...nums];
  for (let i = 0; i < arr.length; i += 1) {
    let swapped = false;
    for (let j = 0; j < arr.length - i - 1; j += 1) {
      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
        swapped = true;
      }
    }
    if (!swapped) break;
  }
  return arr;
}

export function selectionSort(nums) {
  const arr = [...nums];
  for (let i = 0; i < arr.length; i += 1) {
    let minIdx = i;
    for (let j = i + 1; j < arr.length; j += 1) {
      if (arr[j] < arr[minIdx]) minIdx = j;
    }
    [arr[i], arr[minIdx]] = [arr[minIdx], arr[i]];
  }
  return arr;
}

export function insertionSort(nums) {
  const arr = [...nums];
  for (let i = 1; i < arr.length; i += 1) {
    const key = arr[i];
    let j = i - 1;
    while (j >= 0 && arr[j] > key) {
      arr[j + 1] = arr[j];
      j -= 1;
    }
    arr[j + 1] = key;
  }
  return arr;
}

export function quickSort(nums) {
  if (nums.length <= 1) return [...nums];
  const pivot = nums[Math.floor(nums.length / 2)];
  const left = nums.filter((n) => n < pivot);
  const mid = nums.filter((n) => n === pivot);
  const right = nums.filter((n) => n > pivot);
  return [...quickSort(left), ...mid, ...quickSort(right)];
}

export function heapSort(nums) {
  const arr = [...nums];

  const heapify = (n, i) => {
    let largest = i;
    const left = i * 2 + 1;
    const right = i * 2 + 2;
    if (left < n && arr[left] > arr[largest]) largest = left;
    if (right < n && arr[right] > arr[largest]) largest = right;
    if (largest !== i) {
      [arr[i], arr[largest]] = [arr[largest], arr[i]];
      heapify(n, largest);
    }
  };

  for (let i = Math.floor(arr.length / 2) - 1; i >= 0; i -= 1) heapify(arr.length, i);
  for (let end = arr.length - 1; end > 0; end -= 1) {
    [arr[0], arr[end]] = [arr[end], arr[0]];
    heapify(end, 0);
  }
  return arr;
}

export function countingSort(nums) {
  if (!nums.length) return [];
  const max = Math.max(...nums);
  const counts = Array(max + 1).fill(0);
  for (const n of nums) counts[n] += 1;
  const out = [];
  for (let i = 0; i <= max; i += 1) {
    while (counts[i] > 0) {
      out.push(i);
      counts[i] -= 1;
    }
  }
  return out;
}

export function linearSearch(nums, target) {
  for (let i = 0; i < nums.length; i += 1) {
    if (nums[i] === target) return i;
  }
  return -1;
}

export function treeTraversals(tree) {
  const preorder = [];
  const inorder = [];
  const postorder = [];

  const walk = (index) => {
    if (index >= tree.length || tree[index] === null || tree[index] === undefined) return;
    const val = tree[index];
    preorder.push(val);
    walk(index * 2 + 1);
    inorder.push(val);
    walk(index * 2 + 2);
    postorder.push(val);
  };

  if (tree.length) walk(0);
  return { preorder, inorder, postorder };
}

export function dijkstra(graph, start) {
  const dist = { [start]: 0 };
  const visited = new Set();

  while (visited.size < Object.keys(dist).length) {
    let curr = null;
    let best = Infinity;
    for (const [node, d] of Object.entries(dist)) {
      if (!visited.has(node) && d < best) {
        best = d;
        curr = node;
      }
    }
    if (curr === null) break;
    visited.add(curr);
    for (const [neighbor, weight] of graph[curr] || []) {
      const next = best + weight;
      if (!(neighbor in dist) || next < dist[neighbor]) dist[neighbor] = next;
    }
  }
  return dist;
}

export function fibonacciMemo(n, memo = {}) {
  if (n in memo) return memo[n];
  if (n <= 1) return n;
  memo[n] = fibonacciMemo(n - 1, memo) + fibonacciMemo(n - 2, memo);
  return memo[n];
}

export function radixSort(nums) {
  if (!nums.length) return [];
  const arr = [...nums];
  const max = Math.max(...arr);
  let exp = 1;
  while (Math.floor(max / exp) > 0) {
    const buckets = Array.from({ length: 10 }, () => []);
    for (const n of arr) {
      const digit = Math.floor(n / exp) % 10;
      buckets[digit].push(n);
    }
    arr.length = 0;
    for (const bucket of buckets) arr.push(...bucket);
    exp *= 10;
  }
  return arr;
}

export function bellmanFord(graph, start) {
  const dist = {};
  for (const node of Object.keys(graph)) dist[node] = null;
  dist[start] = 0;

  const edges = [];
  for (const [u, neighbors] of Object.entries(graph)) {
    for (const [v, w] of neighbors) edges.push([u, v, w]);
  }

  const nodes = Object.keys(graph);
  for (let i = 0; i < nodes.length - 1; i += 1) {
    for (const [u, v, w] of edges) {
      if (dist[u] !== null && (dist[v] === null || dist[u] + w < dist[v])) {
        dist[v] = dist[u] + w;
      }
    }
  }

  for (const [u, v, w] of edges) {
    if (dist[u] !== null && dist[v] !== null && dist[u] + w < dist[v]) {
      return { distances: null, hasNegativeCycle: true };
    }
    if (dist[u] !== null && dist[v] === null && dist[u] + w < 0) {
      return { distances: null, hasNegativeCycle: true };
    }
  }

  return { distances: dist, hasNegativeCycle: false };
}

